-  const resp = (await promise) as {
-    url?: () => string;
-    status?: () => number;
-    headers?: () => Record<string, string>;
-    body?: () => Promise<Buffer>;
-    text?: () => Promise<string>;
-  };
-
-  const url = resp.url?.() || "";
-  const status = resp.status?.();
-  const headers = resp.headers?.();
-
-  let bodyText = "";
-  try {
-    if (typeof resp.text === "function") {
